using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ───────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith("(555)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsHyphen()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesPattern()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ───────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_NameOnly_UsesDefaultTitle()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_UsesProvidedTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.StartsWith("Dear Dr.", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Doe", "Ms.");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Lee");

        Assert.StartsWith("Dear", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_ContainsName()
    {
        var result = _formatter.BuildGreeting("Williams");

        Assert.Contains("Williams", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhiteSpace_Throws(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ────────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_StripsAndHyphenates()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_Result_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My First Blog Post!");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingSpaces_TrimsCleanly()
    {
        var result = _formatter.GenerateSlug("  padded title  ");

        Assert.AreEqual("padded-title", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhiteSpace_Throws(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ──────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces_EndsWithDecimals()
    {
        var result = _formatter.FormatCurrency(5m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_ExactValue_ReturnsFormattedString()
    {
        var result = _formatter.FormatCurrency(1234.56m);

        Assert.AreEqual("$1234.56", result);
    }

    [TestMethod]
    public void FormatCurrency_AnyAmount_MatchesCurrencyPattern()
    {
        var result = _formatter.FormatCurrency(42.10m, "£");

        Assert.MatchesRegex(@"^£\d+\.\d{2}$", result);
    }

    [TestMethod]
    [DataRow(0, "$0.00")]
    [DataRow(-5.5, "$-5.50")]
    public void FormatCurrency_EdgeCases_ReturnsExpected(double amount, string expected)
    {
        var result = _formatter.FormatCurrency((decimal)amount);

        Assert.AreEqual(expected, result);
    }
}

