    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces_EndsWithDecimals()
    {
        var result = _formatter.FormatCurrency(5m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_ExactValue_ReturnsFormattedString()
    {
        var result = _formatter.FormatCurrency(1234.56m);

        Assert.AreEqual("$1234.56", result);
    }

    [TestMethod]
    public void FormatCurrency_AnyAmount_MatchesCurrencyPattern()
    {
        var result = _formatter.FormatCurrency(42.10m, "£");

        Assert.MatchesRegex(@"^£\d+\.\d{2}$", result);
    }

    [TestMethod]
    [DataRow(0, "$0.00")]
    [DataRow(-5.5, "$-5.50")]
    public void FormatCurrency_EdgeCases_ReturnsExpected(double amount, string expected)
    {
        var result = _formatter.FormatCurrency((decimal)amount);

        Assert.AreEqual(expected, result);
    }
}

